function loadMenu() {
    menuGrid.innerHTML = MENU.map(item => `
        <div class="menu-item">
            <!-- Agregamos el onclick y un cursor de puntero -->
            <img src="${item.foto}" alt="${item.nombre}" 
                 onclick='abrirModal(${JSON.stringify(item)})' 
                 style="cursor:pointer;">
            <div class="info">
                <h2>${item.nombre}</h2>
                <div class="descripcion-container">
                    <p class="descripcion-texto">${item.descripcion}</p>
                </div>
                <div class="price-row">
                    <span class="price">$${item.precio}</span>
                    <div class='agregado'>
                        <button class="btn-add" onclick="restar(${item.id})">-</button>
                        <span id='contador-${item.id}'>${item.cantidad || 0}</span>
                        <button class="btn-add" onclick="sumar(${item.id})">+</button>
                    </div>
                </div>
            </div>
        </div>
    `).join('');
}


function sumar(id) {
    const producto = MENU.find(p => p.id === id);
    console.log(producto)
    if (!producto.cantidad) producto.cantidad = 0;
    if (producto.cantidad < 10) {
        producto.cantidad++
        addToCart(id)
        document.getElementById('contador-' + id).innerText = producto.cantidad;
    } else {
        alert("¡Llegaste al límite de 10!");
    }
    console.log(producto)
}

function restar(id) {
    const producto = MENU.find(p => p.id === id);
    if (!producto.cantidad) producto.cantidad = 0;
    if (producto.cantidad > 0) {
        producto.cantidad--;
        removeToCart(id)
        document.getElementById('contador-' + id).innerText = producto.cantidad;
    }
}
function toggleDireccion() {
    const tipoEntrega = document.getElementById('tipo-entrega').value;
    const contenedorDireccion = document.getElementById('contenedor-direccion');
    const inputDireccion = document.getElementById('cliente-direccion');

    if (tipoEntrega === 'retiro') {
        contenedorDireccion.style.display = 'none';
        inputDireccion.required = false;
        inputDireccion.value = ''; // Limpia el texto si el usuario escribió algo
    } else {
        contenedorDireccion.style.display = 'block';
        inputDireccion.required = true;
    }
}




