   function addToCart(id) {
  const product = MENU.find(p => p.id == id);
  // Buscamos si ya existe en el carrito
  const existingItem = cart.find(item => item.id == id);

  if (existingItem) {
    // Si existe, aumentamos su cantidad
    existingItem.cantidad += 1;
  } else {
    // Si es nuevo, lo agregamos con cantidad 1
    // IMPORTANTE: Eliminamos 'cartId: Date.now()' porque ahora usamos el 'id' original
    cart.push({ ...product, cantidad: 1 });
  }
  
  updateUI();
}

 function removeToCart(id) {
  // Buscamos si el producto existe en el carrito
  const existingItem = cart.find(item => item.id == id);

  if (existingItem) {
    // Si hay más de uno, restamos la cantidad
    if (existingItem.cantidad > 1) {
      existingItem.cantidad -= 1;
    } else {
      // Si queda solo uno, lo eliminamos por completo del carrito
      cart = cart.filter(item => item.id != id);
    }
  }
  
  updateUI();
}

 

function updateUI() {
  const bar = document.getElementById('cart-bar');
  const count = document.getElementById('cart-count');
  
  // Sumamos todas las cantidades
  const totalItems = cart.reduce((acc, item) => acc + item.cantidad, 0);

  if (totalItems > 0) {
    bar.classList.remove('cart-hidden');
    count.innerText = totalItems;
  } else {
    bar.classList.add('cart-hidden');
    toggleModal(true);
  }
  renderSummary();
}   
function renderSummary() {
  const list = document.getElementById('cart-items-list');
  const totalEl = document.getElementById('modal-total');
  let total = 0;

  list.innerHTML = cart.map(item => {
    const subtotal = item.precio * item.cantidad;
    total += subtotal;
    const precio = item.precio
    return `
      <div class="summary-item">
        <div class='margen-bottom'>
          <span style='font-size:1.3rem'>${item.nombre} <strong>( x${item.cantidad} )</strong></span><br>
          <small style="color: var(--naranja);font-size:1.3rem">$${precio}</small>
        </div>
        
      </div>
    `;
  }).join('');

  totalEl.innerText = `$${total}`;
}

function removeFromCart(id) {
  // Filtramos por el id del producto
  cart = cart.filter(item => item.id != id);
  updateUI();
}

function toggleModal(forceClose = false) {
        const modal = document.getElementById('cart-modal');
        if (forceClose) modal.classList.add('modal-hidden');
        else modal.classList.toggle('modal-hidden');
    }

function sendOrder() {
    if (cart.length === 0) {
        Swal.fire({
            title: 'Faltan datos',
            text: 'No hay productos en el carrito.',
            icon: 'warning',
            confirmButtonText: 'Ok',
        });
        return;
    }

    const nombre = document.getElementById("cliente-nombre").value.trim();
    const direccion = document.getElementById("cliente-direccion").value.trim();
    const pago = document.getElementById("cliente-pago").value;
    const observaciones = document.getElementById("cliente-observaciones").value.trim();
    const tipoEntrega = document.querySelector('#tipo-entrega').value
    if (nombre === "") {
        Swal.fire({
            title: 'Faltan datos',
            text: 'Por favor, ingresá tu nombre.',
            icon: 'warning',
            confirmButtonText: 'Ok',
        });
        return;
    }
 if (tipoEntrega !== 'retiro' && direccion === "") {
    Swal.fire({
        title: '¡Falta la dirección!',
        text: 'Por favor, completá tu dirección para poder enviarte el pedido.',
        icon: 'warning',
        confirmButtonText: 'Entendido',
        confirmButtonColor: '#3085d6' // Podés poner el color de tu marca
    });
    return; // Corta la ejecución
}

    if (!pago) {
        Swal.fire({
        title: '¡Faltan datos!',
        text: 'Por favor, selecciona un metodo de pago.',
        icon: 'warning',
        confirmButtonText: 'Entendido',
        confirmButtonColor: '#3085d6' // Podés poner el color de tu marca
    });
    return; // Corta la ejecución
    }

    let total = 0;

    let mensaje = "*PEDIDO AHUMADOS CAMPANA*\n\n";

    mensaje += `Cliente: ${nombre}\n`;
    mensaje += `Dirección: ${direccion}\n`;
    mensaje += `Pago: ${pago}\n\n`;

    mensaje += "*PRODUCTOS:*\n";

    cart.forEach(item => {
        const subtotal = item.precio * item.cantidad;
        total += subtotal;

        mensaje += `- ${item.nombre} x${item.cantidad} = $${subtotal}\n`;
    });

    mensaje += `\n*TOTAL: $${total}*`;

    // 👇 agregar observaciones SOLO si hay texto
    if (observaciones) {
        mensaje += `\n\n*OBSERVACIONES:*\n${observaciones}`;
    }

    const telefono = "5493489558201";

    const url = `https://wa.me/${telefono}?text=${encodeURIComponent(mensaje)}`;

    window.open(url, "_blank");
}
function abrirModal(item) {
    const modal = document.getElementById('modal-detalle');
    document.getElementById('modal-img').src = item.foto;
    document.getElementById('modal-nombre').innerText = item.nombre;
    document.getElementById('modal-descripcion').innerText = item.descripcion;
    
    modal.style.display = "flex";
     // Muestra el modal
}

function cerrarModal(event) {
    const modal = document.getElementById('modal-detalle');
    // Cierra si hace clic en la X o fuera del contenido blanco
    if (event.target === modal || event.target.className === 'close-btn') {
        modal.style.display = "none";
    }
}
